class Solution {
public:
    string strWithout3a3b(int a, int b) {
        string res;
        while (a > 0 || b > 0) {
            if (a >= 2 && b > 0) {
                res += "aab";
                a -= 2;
                b--;
            } else if (a > 0) {
                res += "a";
                a--;
            } else if (b > 0) {
                res += "b";
                b--;
            } else {
                res += "a";
                a--;
            }
        }
        return res;
    }
};
```
